import React, { useEffect, useMemo, useState } from "react";
import { BriefcaseBusiness, CalendarDays, Search, UploadCloud } from "lucide-react";
import { vendorAPI, formatDate, money, safeArray } from "../../services/api.js";
import { routeLabel, moveTypeLabel } from "../../utils/mappers.js";
import { useToast } from "../../components/ui/Toast.jsx";
import Modal from "../../components/ui/Modal.jsx";
import { FormGrid, TextArea, TextInput } from "../../components/ui/Form.jsx";
import { CardPanel, PageHeader, StatusPill } from "../../components/ui/PortalUI.jsx";

export default function VendorNewLeadsPage() {
  const { showToast } = useToast(); const [leads,setLeads]=useState([]); const [keyword,setKeyword]=useState(""); const [lead,setLead]=useState(null); const [form,setForm]=useState({quote_amount:"",availability_from:"",availability_to:"",number_of_movers:"2",insurance_summary:"Goods in Transit and Public Liability",goods_in_transit_cover:"£50,000",public_liability_cover:"£1,000,000",van_details:"Luton van with tail lift",additional_notes:""});
  const load=async()=>{try{setLeads(safeArray(await vendorAPI.leads({status:"assigned"})))}catch(e){showToast(e.message,"error")}}; useEffect(()=>{load()},[]);
  const rows=useMemo(()=>leads.filter((x)=>{const m=x.move||x; return [m.job_id,m.pickup_postcode,m.delivery_postcode,m.status,x.status].filter(Boolean).join(" ").toLowerCase().includes(keyword.toLowerCase())}),[leads,keyword]);
  const submit=async(e)=>{e.preventDefault(); try{const m=lead.move||lead; await vendorAPI.submitQuote({...form,move_request_id:m.id,currency:"GBP"}); showToast("Quote uploaded / submitted"); setLead(null); await load();}catch(err){showToast(err.message,"error")}};
  return <div className="page-wrap"><PageHeader icon={BriefcaseBusiness} title="New Leads / Quote Requests Received" subtitle="Quote requests received from customers." search={keyword} onSearch={setKeyword} placeholder="Search by job, customer or location..."/><CardPanel title="New Leads" subtitle="Manual quote upload and confirmation workflow."><div className="table-scroll"><table><thead><tr><th>Job ID</th><th>Move Type</th><th>Route</th><th>Date</th><th>Budget</th><th>Status</th><th>Action</th></tr></thead><tbody>{rows.map((x)=>{const m=x.move||x; return <tr key={x.id||m.id}><td><b>{m.job_id}</b></td><td>{moveTypeLabel(m.move_type)}</td><td>{routeLabel(m.pickup_postcode,m.delivery_postcode)}</td><td><CalendarDays size={13}/>{formatDate(m.moving_date)}</td><td>{money(m.budget||m.deposit_required||50)}</td><td><StatusPill value={x.status||m.status||"new"}/></td><td><button className="tiny-btn blue-fill" onClick={()=>setLead(x)}>Upload Quote</button></td></tr>})}</tbody></table>{!rows.length?<div className="empty-state">No new leads found.</div>:null}</div></CardPanel><Modal open={!!lead} title="Manual Quote Upload" onClose={()=>setLead(null)} size="lg"><form onSubmit={submit}><section className="form-section"><div className="form-section-head"><UploadCloud size={19}/><div><h3>Quote Actions</h3><p>Confirm availability, confirm pricing and upload quote details.</p></div></div><FormGrid><TextInput label="Quote Amount" value={form.quote_amount} onChange={(v)=>setForm({...form,quote_amount:v})}/><TextInput label="Available From" type="date" value={form.availability_from} onChange={(v)=>setForm({...form,availability_from:v})}/><TextInput label="Available To" type="date" value={form.availability_to} onChange={(v)=>setForm({...form,availability_to:v})}/><TextInput label="Number of Movers" value={form.number_of_movers} onChange={(v)=>setForm({...form,number_of_movers:v})}/><TextInput label="Goods in Transit Cover" value={form.goods_in_transit_cover} onChange={(v)=>setForm({...form,goods_in_transit_cover:v})}/><TextInput label="Public Liability Cover" value={form.public_liability_cover} onChange={(v)=>setForm({...form,public_liability_cover:v})}/></FormGrid><TextInput label="Van Details" value={form.van_details} onChange={(v)=>setForm({...form,van_details:v})}/><TextArea label="Insurance Summary" value={form.insurance_summary} onChange={(v)=>setForm({...form,insurance_summary:v})}/><TextArea label="Notes" value={form.additional_notes} onChange={(v)=>setForm({...form,additional_notes:v})}/></section><div className="modal-actions"><button type="button" className="outline-btn" onClick={()=>setLead(null)}>Cancel</button><button className="red-btn">Send Quote</button></div></form></Modal></div>
}
